### 3. WebSocket 安全配置缺失 🔴

**问题描述**: 
WebSocket 连接未使用 WSS (加密连接)，缺少身份验证和授权机制

**证据**:
```typescript
// dashboard/src/utils/websocket-manager.ts:82
this.ws = new WebSocket(this.url)  // 使用 ws:// 而非 wss://

// dashboard/src/utils/websocket-manager.ts:386
const wsUrl = url || import.meta.env.VITE_WS_URL || 'ws://localhost:3000/api/ws'
```

**风险等级**: 🔴 **高危**

**影响**:
- 数据在传输过程中可被窃听
- 中间人攻击 (MITM)
- 未授权访问
- 跨站 WebSocket 劫持 (CSWSH)

**修复建议**:

```typescript
// ✅ WebSocket 安全配置

// 1. 添加 WebSocket 认证
export interface WebSocketAuthConfig {
  token: string;
  protocol: 'wss' | 'ws';
}

export class SecureWebSocketManager extends WebSocketManager {
  constructor(url: string, authConfig: WebSocketAuthConfig) {
    // 强制使用 WSS (生产环境)
    const secureUrl = process.env.NODE_ENV === 'production' 
      ? url.replace('ws://', 'wss://')
      : url;

    // 添加认证令牌到 URL
    const authenticatedUrl = `${secureUrl}?token=${authConfig.token}`;

    super(authenticatedUrl, {
      // WebSocket 子协议验证
      protocols: ['ai-dev-team-v1']
    });
  }

  protected connect(): void {
    const ws = new WebSocket(this.url, ['ai-dev-team-v1']);

    // 验证子协议
    if (ws.protocol !== 'ai-dev-team-v1') {
      throw new SecurityError('WebSocket protocol negotiation failed');
    }

    // 添加消息验证
    ws.onmessage = (event) => {
      try {
        const message = JSON.parse(event.data);

        // 验证消息签名
        if (!this.verifyMessageSignature(message)) {
          console.error('[WS] Invalid message signature');
          return;
        }

        this.handleMessage(event);
      } catch (error) {
        console.error('[WS] Message validation failed:', error);
      }
    };
  }

  private verifyMessageSignature(message: any): boolean {
    // 使用 HMAC 验证消息完整性
    const signature = message.signature;
    const payload = JSON.stringify(message.data);
    const expectedSignature = this.hmac(payload);

    return signature === expectedSignature;
  }
}

// 2. 服务器端实现 (后端)
import { createServer } from 'http';
import { WebSocketServer } from 'ws';
import jwt from 'jsonwebtoken';

const wss = new WebSocketServer({ 
  path: '/api/ws',
  verifyClient: (info, cb) => {
    // 验证 JWT 令牌
    const token = new URL(info.req.url, 'http://localhost').searchParams.get('token');

    if (!token) {
      cb(false, 401, 'Unauthorized');
      return;
    }

    try {
      const decoded = jwt.verify(token, process.env.JWT_SECRET);
      info.req.user = decoded;
      cb(true);
    } catch (error) {
      cb(false, 401, 'Invalid token');
    }
  }
});

// 3. 消息签名中间件
import crypto from 'crypto';

export function signMessage(data: any, secret: string): string {
  const payload = JSON.stringify(data);
  return crypto.createHmac('sha256', secret).update(payload).digest('hex');
}

export function verifyMessageSignature(data: any, signature: string, secret: string): boolean {
  const expected = signMessage(data, secret);
  return crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expected));
}
```

