### 6. SQL 注入风险 🟡

**问题描述**: 
数据库服务使用原生 SQL，需要验证参数化查询

**证据**:
```typescript
// dashboard/src/dashboard/services/database.service.ts:110
execute(sql: string, params: any[] = []): Database.RunResult {
  // 需要确保所有查询都使用参数化
}
```

**风险等级**: 🟡 **中危**

**修复建议**:

```typescript
// ✅ 安全的查询构建器
import betterSqlite3 from 'better-sqlite3';

export class SecureDatabaseService {
  private db: betterSqlite3.Database;

  constructor(dbPath: string) {
    this.db = new betterSqlite3(dbPath);

    // 启用外键约束
    this.db.pragma('foreign_keys = ON');
  }

  /**
   * 安全的参数化查询
   */
  query<T>(sql: string, params: Record<string, any> = {}): T[] {
    // 验证 SQL 语句
    this.validateSQL(sql);

    // 使用预处理语句
    const stmt = this.db.prepare(sql);
    return stmt.all(params) as T[];
  }

  /**
   * 验证 SQL 语句安全性
   */
  private validateSQL(sql: string): void {
    // 检测危险的 SQL 模式
    const dangerousPatterns = [
      /\bDROP\s+TABLE\b/i,
      /\bDELETE\s+FROM\s+\w+\s*$/i,  // 无 WHERE 的 DELETE
      /\bEXEC\b/i,
      /\bEVAL\b/i,
      /;.*DROP/i,
    ];

    for (const pattern of dangerousPatterns) {
      if (pattern.test(sql)) {
        throw new SecurityError(`Dangerous SQL pattern detected: ${sql}`);
      }
    }

    // 确保使用参数化查询
    if (sql.includes("'") && !sql.includes('?') && !sql.includes('@')) {
      console.warn('[SQL] Possible unparameterized query detected');
    }
  }

  /**
   * 使用 ORM 或查询构建器
   */
  createQueryBuilder(table: string) {
    return new SecureQueryBuilder(this.db, table);
  }
}

class SecureQueryBuilder {
  constructor(private db: betterSqlite3.Database, private table: string) {}

  select(columns: string = '*') {
    const sql = `SELECT ${this.sanitizeColumns(columns)} FROM ${this.escapeId(this.table)}`;
    return new QueryBuilder(this.db, sql);
  }

  where(condition: string, params: Record<string, any>) {
    // 安全的 WHERE 子句构建
  }

  private sanitizeColumns(columns: string): string {
    const allowedColumns = this.getAllowedColumns(this.table);
    const requested = columns.split(',').map(c => c.trim());

    // 只返回允许的列
    return requested
      .filter(c => allowedColumns.includes(c))
      .map(c => this.escapeId(c))
      .join(', ');
  }

  private escapeId(identifier: string): string {
    // SQLite 标识符转义
    return `"${identifier.replace(/"/g, '""')}"`;
  }

  private getAllowedColumns(table: string): string[] {
    // 从白名单返回允许的列
    const schema = {
      iterations: ['id', 'status', 'requirement', 'created_at'],
      agents: ['id', 'name', 'status', 'last_execution_time'],
      // ...
    };

    return schema[table] || [];
  }
}
```

