### 7. 缺少速率限制 🟡

**问题描述**: 
API 和 WebSocket 端点未实现速率限制，易受 DDoS 攻击

**风险等级**: 🟡 **中危**

**修复建议**:

```typescript
// ✅ 速率限制中间件
import rateLimit from 'express-rate-limit';
import { RateLimiterMemory } from 'rate-limiter-flexible';

// HTTP API 速率限制
export const apiRateLimit = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 分钟
  max: 100, // 最多 100 个请求
  message: 'Too many requests from this IP',
  standardHeaders: true,
  legacyHeaders: false,

  // 使用 Redis 存储计数器（生产环境）
  store: process.env.REDIS_URL 
    ? new RedisStore({ client: redisClient })
    : undefined
});

// WebSocket 连接速率限制
const wsLimiter = new RateLimiterMemory({
  points: 10, // 10 个连接
  duration: 60, // 每 60 秒
});

// Agent 执行速率限制（防止滥用）
const agentExecutionLimiter = new RateLimiterMemory({
  points: 5, // 5 次执行
  duration: 300, // 每 5 分钟
});

export async function checkWsRateLimit(ip: string): Promise<boolean> {
  try {
    await wsLimiter.consume(ip);
    return true;
  } catch (rejRes) {
    console.warn(`WebSocket rate limit exceeded for ${ip}`);
    return false;
  }
}

// 应用到 Fastify 服务器
import fastifyRateLimit from '@fastify/rate-limit';

await fastify.register(fastifyRateLimit, {
  max: 100, // 100 请求
  timeWindow: '1 minute',

  // 自定义错误响应
  errorResponseBuilder: (req, context) => ({
    code: 429,
    error: 'Too Many Requests',
    message: `Rate limit exceeded, retry in ${context.after}`,
    retryAfter: context.after
  }),

  // 跳过某些路由
  skipOnError: false,

  // 基于 IP + 用户 ID 限流（更精确）
  keyGenerator: (req) => {
    return req.headers['x-user-id'] as string || req.ip;
  }
});
```

