// src/dashboard/middleware/validation.ts
import { FastifyRequest, FastifyReply } from 'fastify';

export function validatePagination(request: FastifyRequest, reply: FastifyReply) {
  const query = request.query as any;

  const page = parseInt(query.page) || 1;
  const limit = parseInt(query.limit) || 20;

  if (page < 1 || page > 10000) {
    return reply.code(400).send({
      success: false,
      error: { message: 'Invalid page number', code: 'INVALID_INPUT' }
    });
  }

  if (limit < 1 || limit > 100) {
    return reply.code(400).send({
      success: false,
      error: { message: 'Invalid limit (min: 1, max: 100)', code: 'INVALID_INPUT' }
    });
  }

  (request as any).pagination = { page, limit };
}
