   */
  private saveHistoryToFile(): void {
    if (!this.historyFile) return;

    setImmediate(async () => {
      try {
        const fs = require('fs').promises;
        const path = require('path');

        // 确保目录存在
        const dir = path.dirname(this.historyFile);
        await fs.mkdir(dir, { recursive: true });

        // ✅ 安全增强：脱敏敏感信息
        const sanitizedHistory = this.fullHistory.map(entry => ({
          ...entry,
          content: sanitizer.sanitize(entry.content)
        }));

        // ✅ 安全增强：设置文件权限（仅所有者可读写）
        await fs.writeFile(
          this.historyFile!,
          JSON.stringify(sanitizedHistory, null, 2),
          { 
            mode: 0o600, // -rw-------
            encoding: 'utf-8'
          }
        );

        this.logger.info('History saved securely', { file: this.historyFile });
      } catch (err: any) {
        this.logger.error('Failed to save history', err);
      }
    });
  }
}
