// 方案 1: 使用 SQLCipher 加密数据库
import Database from 'better-sqlite3';
import sqlcipher from '@craftsman/sqlcipher';

function initDatabase(databasePath: string) {
  const db = new Database(databasePath);

  // 设置加密密钥（从环境变量获取）
  const encryptionKey = process.env.DB_ENCRYPTION_KEY;
  if (!encryptionKey) {
    throw new Error('DB_ENCRYPTION_KEY not set');
  }

  // 启用加密
  db.pragma(`key = '${encryptionKey}'`);

  return db;
}

// 方案 2: 使用文件系统权限保护
import fs from 'fs';
import path from 'path';

function secureDatabaseFile(databasePath: string) {
  // 设置数据库文件权限为仅所有者可读写
  fs.chmodSync(databasePath, 0o600);

  // 确保数据库目录权限正确
  const dbDir = path.dirname(databasePath);
  fs.chmodSync(dbDir, 0o700);
}
```

