**修复建议**:

```typescript
import crypto from 'crypto';
import fs from 'fs/promises';
import path from 'path';

class SecureHistoryManager {
  private encryptionKey: Buffer;
  private historyDir: string;

  constructor(encryptionKey: string, historyDir: string) {
    // 从环境变量获取加密密钥
    this.encryptionKey = Buffer.from(encryptionKey, 'hex');
    this.historyDir = historyDir;
  }

  // 加密历史记录
  private encrypt(data: string): string {
    const iv = crypto.randomBytes(16);
    const cipher = crypto.createCipheriv('aes-256-gcm', this.encryptionKey, iv);

    let encrypted = cipher.update(data, 'utf8', 'hex');
    encrypted += cipher.final('hex');

    const authTag = cipher.getAuthTag();

    return JSON.stringify({
      iv: iv.toString('hex'),
      data: encrypted,
      authTag: authTag.toString('hex')
    });
  }

  // 解密历史记录
  private decrypt(encryptedData: string): string {
    const { iv, data, authTag } = JSON.parse(encryptedData);

    const decipher = crypto.createDecipheriv(
      'aes-256-gcm',
      this.encryptionKey,
      Buffer.from(iv, 'hex')
    );

    decipher.setAuthTag(Buffer.from(authTag, 'hex'));

    let decrypted = decipher.update(data, 'hex', 'utf8');
    decrypted += decipher.final('utf8');

    return decrypted;
  }

  // 保存加密的历史记录
  async saveHistory(agentName: string, history: any[]): Promise<void> {
    const historyPath = path.join(this.historyDir, `${agentName}.enc`);

    // 确保目录存在
    await fs.mkdir(this.historyDir, { recursive: true });

    // 加密并保存
    const encrypted = this.encrypt(JSON.stringify(history));
    await fs.writeFile(historyPath, encrypted, { mode: 0o600 });
  }

  // 读取并解密历史记录
  async loadHistory(agentName: string): Promise<any[]> {
    const historyPath = path.join(this.historyDir, `${agentName}.enc`);

    try {
      const encrypted = await fs.readFile(historyPath, 'utf-8');
      const decrypted = this.decrypt(encrypted);
      return JSON.parse(decrypted);
    } catch (error) {
      // 文件不存在或解密失败
      return [];
    }
  }
}

// 使用示例
const historyManager = new SecureHistoryManager(
  process.env.HISTORY_ENCRYPTION_KEY!,
  '.ai-history'
);
```

