const wsConnectionLimiter = new Map();

function checkWsConnectionLimit(ip: string): boolean {
  const connections = wsConnectionLimiter.get(ip) || 0;

  if (connections >= 10) {  // 每个 IP 最多 10 个并发连接
    return false;
  }

  wsConnectionLimiter.set(ip, connections + 1);
