### 🔧 技术方案

#### **方案 A：API Key 认证（推荐 - 最小改动）**

```typescript
// 1. 新增认证中间件
// src/dashboard/middleware/auth.ts

export async function validateApiKey(request: FastifyRequest, reply: FastifyReply) {
  const apiKey = request.headers['x-api-key'];

  if (!apiKey) {
    return reply.status(401).send({
      success: false,
      error: { message: 'Missing API Key', code: 'UNAUTHORIZED' }
    });
  }

  // 从环境变量或数据库验证
  const validKeys = process.env.API_KEYS?.split(',') || [];

  if (!validKeys.includes(apiKey)) {
    return reply.status(403).send({
      success: false,
      error: { message: 'Invalid API Key', code: 'FORBIDDEN' }
    });
  }
}

// 2. 应用到路由
// routes/index.ts
export async function registerRoutes(...) {

  // 保护所有 API 路由
  fastify.addHook('onRequest', validateApiKey);

  // 健康检查例外
  fastify.get('/health', async (request, reply) => {
    return reply.send(await systemService.getHealthStatus());
  });
}

// 3. WebSocket 认证
// server.ts
fastify.get('/api/ws', { websocket: true }, async (connection, req) => {
  const apiKey = new URL(req.url, `http://${req.headers.host}`)
    .searchParams.get('api_key');

  if (!isValidApiKey(apiKey)) {
    connection.socket.close(1008, 'Invalid API Key');
    return;
  }

  // 认证成功
  realtimeService.addClient(connection.socket);
});
```

**优点**：
- ✅ 实现简单（~100 行代码）
- ✅ 无需数据库改动
- ✅ 向后兼容（可配置为可选）
- ✅ 2-3 天可完成

**缺点**：
- ⚠️ 安全性中等（需妥善保管 API Key）

