2. **JWT 服务** (`auth/jwt.service.ts`):
```typescript
import jwt from 'jsonwebtoken';

export class JWTService {
  private secret: string;
  private accessTokenExpiry = '15m';
  private refreshTokenExpiry = '7d';

  constructor() {
    this.secret = process.env.JWT_SECRET || 'your-secret-key-change-in-production';
  }

  generateAccessToken(userId: number, role: string): string {
    return jwt.sign(
      { userId, role, type: 'access' },
      this.secret,
      { expiresIn: this.accessTokenExpiry }
    );
  }

  generateRefreshToken(userId: number): string {
    return jwt.sign(
      { userId, type: 'refresh' },
      this.secret,
      { expiresIn: this.refreshTokenExpiry }
    );
  }

  verifyToken(token: string): any {
    try {
      return jwt.verify(token, this.secret);
    } catch (error) {
      return null;
    }
  }
}
```

3. **认证中间件** (`auth/middleware.ts`):
```typescript
import { FastifyRequest, FastifyReply } from 'fastify';

export async function authenticateToken(
  request: FastifyRequest,
  reply: FastifyReply
) {
  const authHeader = request.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Bearer TOKEN

  if (!token) {
    return reply.status(401).send({
      success: false,
      error: { message: 'Access token required', code: 'UNAUTHORIZED' }
    });
  }

  const jwtService = new JWTService();
  const decoded = jwtService.verifyToken(token);

  if (!decoded || decoded.type !== 'access') {
    return reply.status(403).send({
      success: false,
      error: { message: 'Invalid or expired token', code: 'FORBIDDEN' }
    });
  }

  // 将用户信息附加到 request
  request.user = {
    userId: decoded.userId,
    role: decoded.role
  };
}

export function requireRole(...allowedRoles: string[]) {
  return async (request: FastifyRequest, reply: FastifyReply) => {
    if (!request.user) {
      return reply.status(401).send({
        success: false,
        error: { message: 'Authentication required', code: 'UNAUTHORIZED' }
      });
    }

    if (!allowedRoles.includes(request.user.role)) {
      return reply.status(403).send({
        success: false,
        error: { message: 'Insufficient permissions', code: 'FORBIDDEN' }
      });
    }
  };
}
```

4. **认证路由** (`routes/auth.routes.ts`):
```typescript
import { FastifyInstance } from 'fastify';
import { AuthService } from '../auth/auth.service';

export async function registerAuthRoutes(fastify: FastifyInstance) {
  const authService = new AuthService();

  // 注册
  fastify.post('/auth/register', async (request, reply) => {
    const { username, email, password } = request.body as any;

    const user = await authService.register(username, email, password);

    return reply.code(201).send({
      success: true,
      data: { userId: user.id, username: user.username, email: user.email }
    });
  });

  // 登录
  fastify.post('/auth/login', async (request, reply) => {
    const { username, password } = request.body as any;

    const { accessToken, refreshToken, user } = await authService.login(username, password);

    return reply.send({
      success: true,
      data: {
        accessToken,
        refreshToken,
        user: {
          id: user.id,
          username: user.username,
          role: user.role
        }
      }
    });
  });

  // 刷新 Token
  fastify.post('/auth/refresh', async (request, reply) => {
    const { refreshToken } = request.body as any;

    const tokens = await authService.refreshAccessToken(refreshToken);

    return reply.send({ success: true, data: tokens });
  });
}
```

